from dataclasses import dataclass
from enum import Enum

class DecisionBody(Enum):
    EXEC_STEERING  = "exec_steering"
    RISK_PANEL     = "risk_panel"      # CoE Lead + Ethics + Legal
    TECH_REVIEW    = "tech_review"     # Principal Architect + MLOps
    COE_UNILATERAL = "coe_unilateral"  # CoE Lead alone
    BU_AUTONOMOUS  = "bu_autonomous"   # BU guild lead alone

@dataclass
class DecisionRoute:
    body: DecisionBody
    reason: str
    sla_days: int | None   # None = ad-hoc or scheduled

def route_decision(decision: dict) -> DecisionRoute:
    """
    Route a GenAI program decision to the correct governance body.
    decision keys: type, changes_policy, tier2_triggered, changes_platform,
                   changes_standards, affects_external_jurisdiction
    """
    if decision.get("changes_policy") or decision.get("changes_binding_standard"):
        return DecisionRoute(
            body=DecisionBody.EXEC_STEERING,
            reason="Policy or binding standard change requires Exec Steering ratification",
            sla_days=None,  # Next quarterly meeting or emergency session
        )

    if decision.get("tier2_triggered"):
        return DecisionRoute(
            body=DecisionBody.RISK_PANEL,
            reason="Tier 2 risk gate: CoE Lead + AI Ethics + Legal review required",
            sla_days=5,
        )

    if decision.get("changes_platform") or decision.get("changes_standards"):
        return DecisionRoute(
            body=DecisionBody.TECH_REVIEW,
            reason="Platform or standards change: Tech Review Board (bi-weekly cadence)",
            sla_days=14,  # Next TRB session
        )

    if decision.get("type") in ("rate_limit", "model_registry", "guardrail_update"):
        return DecisionRoute(
            body=DecisionBody.COE_UNILATERAL,
            reason="CoE unilateral authority per charter",
            sla_days=1,
        )

    return DecisionRoute(
        body=DecisionBody.BU_AUTONOMOUS,
        reason="No governance trigger; BU guild decides autonomously",
        sla_days=0,
    )
